provider "aws" {
  region = "us-east-1" # or your preferred region
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/Example.com"
  retention_in_days = 7 # Adjust retention period as needed
}

resource "aws_route53_query_logging_config" "primary" {
  zone_id = aws_route53_zone.primary.zone_id

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn

  cloudwatch_log_roles = [
    aws_iam_role.route53_query_logging.arn // Ensure the IAM role for permissions in AWS
  ]
}

resource "aws_iam_role" "route53_query_logging" {
  name = "route53-query-logging-role"

  assume_role_policy {
    version = "2012-10-17"
    statement = {
      effect = "Allow"
      actions = ["sts:AssumeRole"]
      principals = [
        {
          type        = "Service"
          identifiers = ["route53.amazonaws.com"]
        }
      ]
  }
}

resource "aws_route53_zone" "primary" {
  name = "example.com."
}

resource "aws_route53_query_logging_configuration" "query_logging_policy" {
  role_arn            = aws_iam_role.route53_query_logging.arn
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id              = aws_route53_zone.primary.zone_id
}

