  publicly_accessible  = false
  # Additional configurations like parameter group, option group can be added here.
}

resource "aws_db_instance" "public" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  instance_class       = "db.t2.micro"
  name                 = "mydatabase"
  username             = "user"
  password             = "password"
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = true
  # Additional configurations like parameter group, option group can be added here.
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound traffic on port 3306"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Assuming security groups allow desired access, adjust as necessary
  }
}

resource "aws_route53_zone" "private" {
  name = "private.example.com"
}

resource "aws_route53_zone" "public" {
  name = "public.example.com"
}

resource "aws_route53_record" "private_A_record" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal.example.com"
  type    = "A"

  # Using alias to point to the internal RDS instance endpoint
  // Note that Route 53 Alias records can only be used here directly with ALB, CloudFront, ELB,
  // Elastic Beanstalk (application), EC2, ECS service, or S3 buckets, but internal DNS setup is simplified here
  allow_overwrite = true
  records         = [aws_db_instance.internal.address]  # Placeholder to indicate RDS A record
  ttl             = 60
}

resource "aws_route53_record" "public_A_record" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public.example.com"
  type    = "A"

  # Using alias to point to the public RDS instance endpoint
  allow_overwrite = true
  records         = [aws_db_instance.public.address]  # Placeholder to indicate RDS A record
  ttl             = 60
}

output "internal_db_endpoint" {
  value = aws_db_instance.internal.address
}

output "public_db_endpoint" {
  value = aws_db_instance.public.address
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region = "us-east-1" 
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a VPC for internal resources
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/24"
}


# RDS instances
resource "aws_db_instance" "internal" {
  # Internal DB configuration
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier =  "internal"
  username             = "user"
  password             = "password"
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot  = true
}

resource "aws_db_instance" "public" {
  # Public DB configuration
  publicly_accessible  = true
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier = "public"
  username             = "user"
  password             = "password"
  skip_final_snapshot  = true
}

resource "aws_db_subnet_group" "main" {
  name       = "mydb-subnet-group"
  subnet_ids = [aws_subnet.maina.id, aws_subnet.mainb.id]
}

data "aws_availability_zones" "available" {}

# Subnet for RDS
resource "aws_subnet" "maina" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.0/25"
  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "mainb" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.128/25"
  availability_zone = data.aws_availability_zones.available.names[1]
}

# Route 53 Public Hosted Zone for external users
resource "aws_route53_zone" "public" {
  name = "example53.com"
}

# Route 53 Private Hosted Zone for internal users
resource "aws_route53_zone" "private" {
  name = "example53.com"
  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# Route 53 Record for Public DB (External Endpoint)
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

# Route 53 Record for Internal DB (Internal Endpoint)
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
}

