resource "aws_db_instance" "prod_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "dbuser"
  password             = "prodsecret"
  parameter_group_name = "default.mysql5.7"
