        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_instance_profile" "ec2_eb_profile1" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.ec2_eb_role.name
}

resource "aws_elb" "blue_elb" {
  name               = "blue-elb"
  availability_zones = ["us-west-2a", "us-west-2b"]

  listener {
    instance_port     = 80
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }
}

resource "aws_elb" "green_elb" {
  name               = "green-elb"
  availability_zones = ["us-west-2a", "us-west-2b"]

  listener {
    instance_port     = 80
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }
}

resource "aws_elastic_beanstalk_application" "my_app" {
  name = "my-eb-application"
}

resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.14 running Python 3.8"
  ec2_elb_names       = [aws_elb.blue_elb.name]

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_eb_profile1.name
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.identifier
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = " DBUser"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = " DBPassword"
    value     = aws_db_instance.my_db.password
  }
}

resource "aws_elastic_beanstalk_environment" "green" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.14 running Python 3.8"
  ec2_elb_names       = [aws_elb.green_elb.name]

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_eb_profile1.name
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.identifier
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = " DBUser"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = " DBPassword"
    value     = aws_db_instance.my_db.password
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "null_resource" "db_snapshot" {
  triggers = {
    always_run = "${timestamp()}"
  }

  provisioner "local-exec" {
    command = "aws rds create-db-snapshot --db-instance-identifier ${aws_db_instance.my_db.id} --db-snapshot-identifier my-db-snapshot-timestamp"
  }

  depends_on = [aws_db_instance.my_db]
}
```

**Note**: Replace `your_password` with a secure password for the database. The configuration creates a blue/green deployment setup with Elastic Beanstalk environments (defined under the `aws_elastic_beanstalk_environment` resources) and associated Elastic Load Balancers. The `null_resource` with a `local-exec` provisioner is used to take a snapshot of the database prior to deployment, though this is a simplified approach and may require AWS CLI configured with appropriate permissions.

