resource "aws_vpc" "eb_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_internet_gateway" "eb_igw" {
  vpc_id = aws_vpc.eb_vpc.id
}

resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block         = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block         = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2b"
}

resource "aws_route_table" "eb_route_table" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }
}

resource "aws_route_table_association" "eb_route_table_association_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_route_table.id
}

resource "aws_route_table_association" "eb_route_table_association_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_route_table.id
}

resource "aws_security_group" "eb_env_sg" {
  vpc_id = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "shared_rds" {
  allocated_storage    = 100
  storage_type        = "gp2"
  engine             = "postgres"
  engine_version     = "12.4"
  instance_class     = "db.t3.micro"
  name              = "shared_rds"
  identifier        = "shared-rds"
  username         = "postgres"
  password         = "YourPassword"
  parameter_group  = "default.postgres12.b64"
  skip_final_snapshot = true
  db_subnet_group_name = aws_db_subnet_group.gpg.id

  availability_zone = "us-west-2a"
}

resource "aws_db_subnet_group" "gpg" {
  name                   = "shared-rds-subnet-group"
  description            = "Shared subnet for RDS"
  subnet_ids            = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
  tags = {
    Name = "shared-rds-subnet-group"
  }
}

resource "aws_elastic_beanstalk_environment" "eb_env_1" {
  name                = "my-environment-1"
  solution_stack_name  = "64bit Amazon Linux 2018.03 v2.9.4 running PHP 7.2"
  application         = "my-application"
  version            = "v1"
  instance_type      = "t3.medium"
  instance_count    = 1
  cname            = "environment-1.cname"

  setting {
    namespace = "aws:elasticbeanstalk:application"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "SecurityGroup"
    value     = aws_security_group.eb_env_sg.name
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.shared_rds.identifier
  }
}

resource "aws_elastic_beanstalk_environment" "eb_env_2" {
  name                = "my-environment-2"
  solution_stack_name  = "64bit Amazon Linux 2018.04 v2.9.2 running PHP v7.3"
  application         = "my-application"
  version            = "v2"
  instance_type      = "t3.medium"
  instance_count    = 1
  cname            = "environment-2.cname"

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.shared_rds.identifier
  }
}

resource "aws_elastic_beanstalk_environment" "shared_rds_1_connect" {
  cnames = ["environment-1.cname"] # Connection CNAMEs for the environments
}

resource "aws_elastic_beanstalk_environment" "shared_rds_2_connect" {
  cnames = ["environment-2.cname"]
}

resource "aws_route_table" "eb_route_table" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    gateway_id     = aws_internet_gateway.eb_igw.id
  }
}
```

Explanation:
- The VPC is named `eb_vpc` and uses a CIDR block `10.0.0.0/16`.
- Public subnets (`eb_subnet_public_1` and `eb_subnet_public_2`) are defined within this VPC.
- Security group (`eb_env_sg) allows traffic from public Internet and known ports such as 80 (HTTP) and 22 (SSH), opening necessary ingress for the beanstalk environments.
- A shared RDS DB instance (`shared_rds`) is configured within the VPC in the public subnets.
- The `aws_elastic_beanstalk_environment` resources are configured to link environments to the shared RDS DB, using configuration settings to specify environment and RDS properties.

Remember to duplicate resource names for each environment to ensure the uniqueness of configuration within AWS.

