  ttl     = "300"
  records = ["${aws_elastic_beanstalk_environment.myenv.cname_record}.elasticbeanstalk.com"]
}

# Assuming an Elastic Beanstalk application is deployed and its name follows a certain pattern
data "aws_elastic_beanstalk_application" "myapp_app" {
  application_name = "MyApp"
  environment_name = "myapp_eb_environment"
}

# Configure the Elastic Beanstalk load balancer behavior
resource "aws_elastic_beanstalk_loadbalancer" "myapp_lb_behavior" {
  load_balancer_name = aws_elastic_beanstalk_environment.myenv.load_balancer
  noncurrent_version_routing {
    redirect { 
      redirect_http { method = "302" }
      redirection_hop_limit = "5"
    }
  }
}
