  fulfillment_type = "RETURN_DIALOG"  # Using Amazon Lex in the conversation with AWS Lambda for fulfillment
  slots {
    name      = "PizzaType"
    type      = "AMAZON.NUMBER"
    description = "Type of pizza you want to order"
  }

  slots {
    name = "DeliveryAddress"
    type = "AMAZON.STREET_ADDRESS"
    description = "Address where the pizza should be delivered"
  }

  confirmation_required = false
  sample_utterance = "I would like to order a pizza"
}

resource "aws_lex_intent" "pizza_preferences_intent" {
  name        = "PizzaPreferencesIntent"
  fulfillment_type = "RETURN_DIALOG"
  slots {
    name      = "PizzaToppings"
    type      = "AMAZON.NUMBER"
    description = "Select your pizza toppings"
  }
}

resource "aws_lex_intent" "confirm_order_intent" {
  name        = "ConfirmOrderIntent"
  fulfillment_type = "FULFILLMENT_WITH_RESPONSE"
  slots {
    name      = "OrderConfirmation"
    type      = "AMAZON.YES_NO"
    description = "Confirm your order"
  }
}

resource "aws_lex_intent" "update_order_intent" {
  name        = "UpdateOrderIntent"
  fulfillment_type = "RETURN_DIALOG"
  slots {
    name      = "NewPizzaDetails"
    type      = "AMAZON.NUMBER"
    description = "Update details about your pizza order"
  }
}

resource "aws_lex_intent" "modify_order_intent" {
  name        = "ModifyOrderIntent"
  fulfillment_type = "RETURN_DIALOG"
  slots {
    name      = "ModifiedPizzaDetails"
    type      = "AMAZON.NUMBER"
    description = "Modify your pizza order details"
  }
}

resource "aws_lex_intent" "cancel_order_intent" {
  name        = "CancelOrderIntent"
  slots {
    name = "ReasonForCancellation"
    type = "AMAZON.NUMBER"
    description = "Specify the reason for canceling order"
  }
  fulfillment_type = "FULFILLMENT_WITH_RESPONSE"
  confirmation_required = false
}

resource "aws_lex_bot_alias" "bid_restaurant_app_delivery" {
  name            = "BidRestaurantAlias"
  bot_id          = aws_lex_bot.ordering_pizza_bot.id
  description     = "Alias for the ordering pizza bot with intents for delivery orders application"
}

resource "aws_lex_bot_version" "version" {
  description     = "Initial version of the bot"
