  bot_name = aws_lex_bot.pizza_order_bot.name
  role_arn = "arn:aws:iam::${var.aws_account_id}:role/service-role/myBotRole" # Adjust with your actual IAM role ARN
  code_hook_type = "LexCodeHook"
  description = "Lambda Function for ordering pizzas"
}

resource "aws_lex_bot_alias" "pizza_order_alias" {
  name = "PizzaOrderBotAlias"
  bot_id = aws_lex_bot.pizza_order_bot.id
  role_arn = "arn:aws:iam::${var.aws_account_id}:role/service-role/myBotRoleARN" # Adjust with your actual IAM Role ARN
}

resource "aws_lex_bot_version" "pizza_order_version" {
  version_name = "PizzaOrderBotVersion1"
  bot_id = aws_lex_bot.pizza_order_bot.id
  alias_id = aws_lex_bot_alias.pizza_order_alias.id
  build_execution_arn = "arn:aws:lex:us-east-1:${var.aws_account_id}:bot/${aws_lex_bot.pizza_order_bot.id}/botAlias/id/${aws_lex_bot_alias.pizza_order_alias.id}"

  resource_type = "BOT"
  nlu_intent = "pizza.order" # Replace with your actual intent configured for NLU
  nlu_slot_mapping = [
    {
      slot_name = "PizzaSize"
      slot_type = "SIZE"
      slot_sample_role = "PARENT" # Replace with your actual slot sample role
    },
    {
      slot_name = "PizzaType"
      slot_type = "TYPE"
      slot_sample_role = "CHILD"
    },
  ]
}
```

**Note**: 
- Replace placeholders like `${var.aws_account_id}` with your actual AWS account ID.
- Ensure the Lambda function is configured with required IAM roles and permissions.
- Configure the bot's intents and slots appropriately in AWS Lex for proper bot interaction.

