provider "aws" {
  region = "us-west-2" # Specify your desired AWS region
}

resource "aws_iam_role" "firehose_delivery_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_policy"
  description = "Policy for Kinesis Firehose to access S3 and Elasticsearch"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:*",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ],
        Resource = [
          "arn:aws:s3:::my-kinesis-firehose-data-bucket", # Update with your bucket ARN
          "arn:aws:s3:::my-kinesis-firehose-data-bucket/*",
          "arn:aws:es:us-west-2:123456789012:domain/my-elasticsearch-domain/*" # Update with your Elasticsearch domain ARN
        ],
        Effect = "Allow"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_delivery_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-kinesis-firehose-data-bucket" # Update with your desired bucket name
}

resource "aws_kinesis_firehose_delivery_stream" "my_stream" {
  name        = "my-delivery-stream"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn                  = "arn:aws:es:us-west-2:123456789012:domain/my-elasticsearch-domain" # Update with your Elasticsearch domain ARN
    index_name                  = "my-index"
    role_arn                    = aws_iam_role.firehose_delivery_role.arn
    processing_configuration {
      enabled = "true"
      processors {
        type = "AppendDelimiterToUtf8"
        parameters {
          delimiters = [","]
        }
      }
    }
    s3_configuration {
      role_arn          = aws_iam_role.firehose_delivery_role.arn
      bucket_arn        = aws_s3_bucket.firehose_bucket.arn
      buffer_size       = 10
      buffer_interval   = 300
      compression_format = "GZIP"
    }
  }
}
