        identifiers = ["firehose.amazonaws.com", "lambda.amazonaws.com"]
      }
    }
}

resource "aws_iam_policy" "permission_policy" {
  name   = "opensearch-permission-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "es:*"
        Resource = concat(["arn:aws:es:${var.aws_region}:${data.aws_caller_identity.current_account_id}:domain/${aws_opensearch_domain.firehose_domain.name}", ["/", "*"])
      },
      {
        Effect = "Allow"
        Action = ["es:ESHttpPost*", "es:ESHttpPut*", "es:ESHttpHead*", "es:ESGet*"]
        Resource = ["*"]
      },
    ]
  })
}

resource "aws_iam_policy_attachment" "firehose_policy_attachment" {
  name        = "opensearch-policy-attachment"
  policy_arn   = aws_iam_policy.permission_policy.arn
  roles       = [aws_iam_role.firehose_role.name]
}

resource "aws_opensearch_domain" "firehose_domain" {
  domain_name = "my-firehose-opensearch-domain"
  cluster_config {
    instance_type = "t2.small.elasticsearch"
  }

  ebs_options {
    master_volume_id = "285f026c0f9a67b80eeaa8cf120d876ee"
  }

  tags = {
    Name   = "TerraformNinjaOpensearchDomain"
    Environment = "production"
  }
}

resource "aws_s3_bucket" "firehose_destination" {
  bucket = "my-firehose-opensearch-bucket"
