}

resource "aws_kinesis_firehose_delivery_stream" "example_delivery_stream" {
  name        = "example-delivery-stream"
  role_arn    = aws_iam_role.example. arn
  source_arn  = aws_kinesis_stream.example_kinesis_stream.arn

  s3_configuration {
    role_arn         = aws_iam_role.example.arn
    bucket_arn        = aws_s3_bucket.example.arn
    prefix           = "example/"
    buffering_hints {
      size_in_m_bs = 128 # Required for OpenSearch Destinations
      interval_in_seconds = 900
    }
  }

  kinesis_stream_arn = aws_kinesis_stream.example_kinesis_stream.arn

  delivery_stream_schema = "fields"
  delivery_stream_buffering_hints {
    size_in_mb        = 10
    interval_in_seconds = 300
  }

  destination_config {
    cluster_arn            = aws_opensearch_domain.example_opensearch_domain.arn
    role_arn              = aws_iam_role.example.arn
    s3_configuration {
      bucket_arn = aws_s3_bucket.example.arn
    }
  }
  tags = {
    Environment = "production"
    Name       = "example-delivery-stream"
  }
}

resource "aws_kinesis_stream" "example_kinesis_stream" {
  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = "24 HOURS"
}

