      aws eks --region ${var.region} update-kubeconfig --name ${self.name}
    EOT
  }

  provisioner "local-exec" {
    when    = destroy
    command = <<EOT
      aws eks --region ${var.region} delete-certs --name ${self.name}
      aws eks --region ${var.region} update-kubeconfig --name ${self.name} --delete
    EOT
  }
}
```

