resource "aws_iam_policy" "example_access_policy" {
  name = "example-access-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Action    = [
          "eks:DescribeCluster"
        ]
        Resource = [
          aws_eks_cluster.example_cluster.id
        ]
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
      {
        Effect    = "Allow"
        Action    = [
          "eks:DescribeCluster",
          "eks:ListClusters",
          "eks:AccessKubernetesApiEndpoint"
        ]
        Resource = "*"
        Principal = {
          AWS = ["arn:aws:iam::ACCOUNT_ID:instance-profile/NAME"]
        }
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "example_iam_role_attachment" {
  policy_arn = aws_iam_policy.example_access_policy.arn
  roles = [aws_iam_role.example_role.name]
}

resource "aws_iam_role" "example_role" {
  name = "example-eks-role"

  assume_role_policy {
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = "sts:AssumeRole"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  }

  inline_policy {
