variable "bucket_suffix" {
  type = string
}

provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "cloudgoat_data_storage" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default = true
    }
  }

  ownership_controls {
    rules {
      object_ownership = "ObjectWriter"
      rule {
        apply = true
      }
    }
  }
}

resource "aws_s3_bucket" "web_data_storage" {
  bucket = "webgoat-data-${var.bucket_suffix}"
  acl    = "private"

  tags = {
    "Owner" = "Self"
  }

  policy = data.aws_iam_policy_document.web_data_bucket_policy.json
}

data "aws_iam_policy_document" "web_data_bucket_policy" {
  statement {
    effect    = "Allow"
    actions   = ["s3:PutObject"]
    principals {
      type        = "AWS"
      identifiers = ["*"]
    }
    resources = [
      "arn:aws:s3:::${aws_s3_bucket.web_data_storage.bucket}/*",
    ]
}

resource "aws_s3_bucket_public_access_block" "web_data_public_access_block" {
  bucket = aws_s3_bucket.web_data_storage.id

  block_public_acls  = true
  ignore_public_acls = true
  block_public_policy = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_object" "web_data_object" {
  bucket = aws_s3_bucket.web_data_storage.id
  key    = "order_data2.csv"
  source = "path/to/local/order_data2.csv"
  acl    = "private"
}
