provider "aws" {
  region = "us-east-1"
}

resource "aws_ami" "latest_amazon_linux2" {
  root_device_type = "ebs"

  name = coalesce(
    data.aws_ami.latest_amazon_linux2[count.index].name,
    "${data.aws_ami.latest_amazon_linux2.id}-ami"
  )
  name_prefix = "latest-amazon-linux2-"

  # Get the latest Amazon Linux 2 AMI from the AWS AMI filtering capability
  data "aws_ami" "latest_amazon_linux2" {
    owners      = ["amazon"]
    filters {
      name         = "name"
      values      = ["amzn2-ami-hvm*"]
      filter {
      exists     = true
      }
    }

    most_recent = true
    owners      = ["amazon"]
  }
}

