provider "aws" {
  region = "us-west-2"
}

# Create a new VPC
resource "aws_vpc" "main_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true

  tags = {
    Name = "main_vpc"
  }
}

# Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id     = aws_vpc.main_vpc.id
  cidr_block = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2a"

  tags = {
    Name = "public_subnet"
  }
}

# Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id     = aws_vpc.main_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "private_subnet"
  }
}

# Internet Gateway for the VPC
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "main_igw"
  }
}

# Route Table for the Public Subnet
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public_route_table"
  }
}

# Associate Public Subnet with Route Table
resource "aws_route_table_association" "public_subnet_association" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_route_table.id
}

# EC2 Launch Template
resource "aws_launch_template" "ec2_template" {
  name_prefix = "ec2_template_"

  image_id        = "resolve:ssm:/aws/service/ami-amazon-linux-latest/al2023-ami-kernel-default-x86_64"
  instance_type   = "t3.medium"

  vpc_security_group_ids = [aws_security_group.default_sg.id]

  subnet_id = aws_subnet.private_subnet.id

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "EC2FleetInstance"
    }
  }
}

# Security Group
resource "aws_security_group" "default_sg" {
  vpc_id = aws_vpc.main_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "default_sg"
  }
}

# EC2 Fleet
resource "aws_ec2_fleet" "ec2_fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_template.id
      version            = "$Latest"
    }

    overrides {
      instance_type     = "t3.medium"
      subnet_id         = aws_subnet.private_subnet.id
      max_price         = "0.067" # Spot price, update as necessary
      weight            = 3
      group_set         = [aws_security_group.default_sg.id]
    }
  }

  target_capacity_specification {
    total_target_capacity = 9
    default_target_capacity_type = "instance"
  }

  on_demand_options {
    allocation_strategy = "prioritized"
    capacity_reservation_specification {
      capacity_reservation_preference = "open"
    }
  }

  termination_options {
    instance_retirement_policy = "default"
  }

  instance_pools_to_use_count = 1
}

# Target Capacity for On-Demand and Spot Instances
resource "aws_ec2_fleet" "ec2_fleet_on_demand_spot" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_template.id
      version            = "$Latest"
    }

    overrides {
      instance_type     = "t3.medium"
      max_price         = "0.067" # Spot price, update as necessary
      weight            = 5
      group_set         = [aws_security_group.default_sg.id]
    }

    overrides {
      instance_type     = "t3.medium"
      max_price         = "0" # On-Demand
      weight            = 4
      group_set         = [aws_security_group.default_sg.id]
    }
  }

  target_capacity_specification {
    total_target_capacity = 9
    default_target_capacity_type = "spot"
  }

  on_demand_options {
    allocation_strategy = "lowest_price"
    capacity_reservation_specification {
      capacity_reservation_preference = "open"
    }
  }

  spot_options {
    instance_interruption_behavior = "terminate"
  }

  termination_options {
    instance_retirement_policy = "default"
  }
}

