  vpc_id            = aws_vpc.vpc.id
  cidr_block        = cidrsubnet(aws_vpc.vpc.cidr_block, 4, count.index)
  availability_zone = element(tolist(data.aws_availability_zones.available.names), count.index)
  map_public_ip_on_launch = false
  tags = {
    Name = "private_subnet_${count.index}"
  }
}

resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public_subnet.id
}

resource "aws_eip" "nat" {
  vpc = true
}

resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = cidrsubnet(aws_vpc.vpc.cidr_block, 4, 1)
  availability_zone = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true
  tags = {
    Name = "public_subnet"
  }
}

resource "aws_route_table_association" "private" {
  count = length(aws_subnet.private_subnet)
  subnet_id      = aws_subnet.private_subnet[count.index].id
  route_table_id = aws_route_table.private_route_table.id
}

resource "aws_ecs_cluster" "cluster" {
  name = "private-cluster"
}

data "aws_ami" "linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_efs_file_system" "efs" {
  creation_token = "my-efs"
  tags = {
    Name = "MyEFS"
  }
}

resource "aws_efs_mount_target" "mount_target" {
  count = 2
  file_system_id  = aws_efs_file_system.efs.id
  subnet_id       = aws_subnet.private_subnet[count.index].id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_security_group" "efs_sg" {
  vpc_id = aws_vpc.vpc.id

  ingress {
    protocol    = "tcp"
    from_port   = 2049
    to_port     = 2049
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "ec2_sg" {
  vpc_id = aws_vpc.vpc.id

  ingress {
    protocol    = "tcp"
    from_port   = 22
    to_port     = 22
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "ec2_instance" {
  count = 2

  ami           = data.aws_ami.linux.id
  instance_type = "t2.micro"
  key_name      = "your-key-pair-name"
  subnet_id     = aws_subnet.private_subnet[count.index].id
  private_ips   = ["10.0.0.10"]

  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  provisioner "remote-exec" {
    inline = [
      "sudo yum install -y amazon-linux-extras",
      "sudo amazon-linux-extras install -y nfs-utils"
    ]
  }
}

resource "null_resource" "configure_efs" {
  provisioner "remote-exec" {
    inline = [
      "sudo mkdir /mnt/efs",
      "echo '${aws_efs_file_system.efs.dns_name}:/ /mnt/efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2 0 0' | sudo tee -a /etc/fstab",
      "sudo mount -a"
    ]

    connection {
      type        = "ssh"
      host        = aws_instance.ec2_instance[count.index].public_ip
      user        = "ec2-user"
      private_key = file("path/to/your/private-key.pem")
    }
  }

  triggers = {
    instance_ids = join(",", aws_instance.ec2_instance.*.id)
  }
}

data "aws_availability_zones" "available" {}

resource "aws_security_group_rule" "outbound" {
  for_each = toset(["tcp", "udp"])
  security_group_id        = aws_security_group.ec2_sg.id
  type                     = "egress"
  from_port                = 0
  to_port                  = 0
  protocol                 = each.key
  cidr_blocks              = ["0.0.0.0/0"]
}
