  pgp_key = "example-key"
}

output "elasticache_user_name" {
  value = aws_iam_user.elasticache_user.name
}

output "elasticache_user_password" {
  sensitive = true
  value     = aws_iam_user_login_profile.elasticache_user_profile.password
}
```

**Note:** This code sets up an IAM user for accessing ElastiCache. The password is output securely as a sensitive value. You can customize the `pgp_key` as necessary, or omit it if preference key-based upload is not required.

