provider "aws" {
  region = "us-east-1" # You can change this to your preferred AWS region
}

# IAM Role for the Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy to allow the Lambda to log to CloudWatch
resource "aws_iam_policy" "lambda_logging" {
  name        = "lambda_logging_policy"
  description = "IAM policy for logging from a lambda"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      },
    ]
  })
}

# Attach the logging policy to the IAM role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_logging.arn
}

# Lambda function configuration
resource "aws_lambda_function" "lambda_function" {
  function_name = "my_lambda_function"

  s3_bucket = "your_bucket_name" # Specify your S3 bucket
  s3_key    = "lambda_function.zip" # Specify the S3 key after you upload lambda_function.zip

  handler = "lambda_handler.handler" # Adjust if necessary
  runtime = "nodejs18.x"

  role = aws_iam_role.lambda_role.arn

  source_code_hash = filebase64sha256("lambda_function.zip")

  depends_on = [
    aws_iam_role_policy_attachment.lambda_logs,
  ]
}

# Generate the ZIP archive of the Lambda function source
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function.zip"
}

