}

resource "aws_sagemaker_notebook_instance_lifecycle_configuration" "notebook_configuration" {
  run_support           = ["SOURCE_REPOSITORY", "JUPYTER_SERVER_PROXY"]
  script_resolution    = "sourceVersion" # This could be "sourceCommit", "oldestSupported", or "absoluteTime"
  notebook_task_timeout_seconds = 7200
}

resource "aws_sagemaker_notebook_instance_metadata_options" "notebook_metadata_options" {
  notebook_instance_metadata_field_substitution = {
    "GIT_SSL_VERIFY" = "false"
  }
}

resource "aws_sagemaker_notebook_instance_service_configuration" "notebook_service_configuration" {
  notebook_instance_execution_role_arn = aws_iam_role.notebook_instance_role.  # You need to define an IAM role with appropriate permissions
  permissions_mode = "SageMaker" # This could also be "NoSageMaker"
}

resource "aws_sagemaker_notebook_instance_root_access" "notebook_root_access" {
  root_access = true
}

