  task_id      = "SageMaker"
  input_mapping {
    "Input" = "InputKey"
  }

  start_url = "https://s3.amazonaws.com/my-bucket/input-data"
}

resource "aws_sfn_transition" "sagemaker_transition" {
  from    = "SageMaker"
  to      = "NextTask"
  conditions = {
    self = aws_sfn_task.sagemaker_task. 
  }
}

resource "aws_sfn_arn" "sagemaker_transition" {
  arn   = aws_sfn_task.sagemaker_task.arn
}

