  name   = "my-sagemaker-pipeline"
  role_arn           = "arn:aws:iam::123456789012:role/service-role/AmazonSageMaker-ExecutionRole"
  definition = aws_sfn_arn.sagemaker_transition.arn

  nodes {
    name                         = "my-sageMaker-node"
    data_sources = [
      aws_sfn_event_input_start.arn
