  name           = "dynamodb_table"
  hash_key       = "id"
  range_key      = "sort_key"
  read_capacity  = 5
  write_capacity = 5

  attribute {
    name = "id"
    type = "S"
  }

  attribute {
    name = "sort_key"
    type = "N"
  }

  tags = {
    Name = "DynamoDBTable"
  }

  ttl {
    attributeName = "expiry"
    enabled       = true
    attributeType  = "N"
  }
}

resource "aws_appautoscaling_target" "dynamodb_table_target" {
  service_namespace  = "dynamodb"
  resource_id         = "table/${aws_dynamodb_table.dynamodb_table.name}"
  scalable_dimension = "dynamodb:table:WriteCapacityUnits"
  min_capacity       = 5
  max_capacity       = 20
}

resource "aws_appautoscaling_policy" "write_capacity_policy" {
  name               = "dynamodb_${aws_dynamodb_table.dynamodb_table.name}_write_capacity_policy"
  service_namespace  = "dynamodb"
  resource_id         = aws_appautoscaling_target.dynamodb_table_target.resource_id
  scalable_dimension = aws_appautoscaling_target.dynamodb_table_target.scalable_dimension

  step_scaling_policy {
    adjustment_type = "ChangeInCapacity"
    cooldown       = 60
    min_adjustment = 1

    metric_trigger {
      metric_name = "SuccessfulRequestCount"
      namespace   = "AWS/DynamoDB"
      statistic  = "Sum"
      unit       = "Count"

      dimensions {
        name  = "Table"
        value = aws_dynamodb_table.dynamodb_table.name
      }

      abovelimit {
        perunit = 1000
      }
    }
  }
}

