provider "google" {
  project = "your-gcp-project-id"
  region  = "us-east1"
}

resource "google_logging_config" "mks_cluster_logs" {
  name        = "mks-cluster-logs"
  destination = "cloudwatch_logs"

  filter = "resource.type="k8s_cluster" AND severity>=INFO"

  excluded_fields = ["jsonPayload.k8s.context.labels"]

  cloudwatch_logs_destination {
    log_group_arn = "arn:aws:logs:us-east-1:123456789012:log-group:java-kafka"
  }
}

resource "google_container_cluster" "us_east1" {
  name     = "msk-cluster"
  location = "us-east1"

  ip_allocation_policy {
    cluster_secondary_range_name  = "pods"
    services_secondary_range_name = "services"
  }

  master_authorized_networks_config {
    cidr_blocks {
      cidr_block   = "0.0.0.0/0"
      display_name = "Public"
    }
  }

  monitoring_service = "monitoring.googleapis.com/kubernetes"

  logging_service = "logging.googleapis.com/kubernetes"

  addons_config {
    cloudrun_config {
      disabled = false
    }

    http_port_access_policy {
      access = "GRPC_ONLY"
    }

    istio_config {
      disabled = false
    }

    horizontal_pod_autoscaling {
      disabled = false
    }

    kubernetes_dashboard {
      disabled = false
    }
  }

  network    = "default"

  initial_node_count = 3

  labels = {
    env = "production"
  }

  workload_identity_config {
    identity_namespace = "your-gcp-project-id.svc.id.goog"
  }

  dynamic "logging_service" {
    for_each = [
      {
        component = "SYSTEM.METRIC"
        enabled   = true
      },
      {
        component = "SYSTEM_LOG"
        enabled   = true
      },
    ]

    content {
      component                  = logging_service.value.component
      enable_automatic_logging   = true
      exclude_namespaces         = []
      include_namespaces         = ["*"]
      enable_components_in_logs  = {
        workload = ["audit_log"]
      }

      if logging_service.value.component == "SYSTEM_LOG" {
        destination_config {
          log_sink  = google_logging_config.mks_cluster_logs.name
        }
      }
    }
  }
}

