terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_cloudwatch_log_group" "test" {
    name = "msk_broker_logs"
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]

        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }

        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = true
                log_group = aws_cloudwatch_log_group.test.name
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
```hcl
provider "google" {
  project = "your-gcp-project-id"
  region  = "us-east1"
}

resource "google_logging_config" "mks_cluster_logs" {
  name        = "mks-cluster-logs"
  destination = "cloudwatch_logs"

  filter = "resource.type="k8s_cluster" AND severity>=INFO"

  excluded_fields = ["jsonPayload.k8s.context.labels"]

  cloudwatch_logs_destination {
    log_group_arn = "arn:aws:logs:us-east-1:123456789012:log-group:java-kafka"
  }
}

resource "google_container_cluster" "us_east1" {
  name     = "msk-cluster"
  location = "us-east1"

  ip_allocation_policy {
    cluster_secondary_range_name  = "pods"
    services_secondary_range_name = "services"
  }

  master_authorized_networks_config {
    cidr_blocks {
      cidr_block   = "0.0.0.0/0"
      display_name = "Public"
    }
  }

  monitoring_service = "monitoring.googleapis.com/kubernetes"

  logging_service = "logging.googleapis.com/kubernetes"

  addons_config {
    cloudrun_config {
      disabled = false
    }

    http_port_access_policy {
      access = "GRPC_ONLY"
    }

    istio_config {
      disabled = false
    }

    horizontal_pod_autoscaling {
      disabled = false
    }

    kubernetes_dashboard {
      disabled = false
    }
  }

  network    = "default"

  initial_node_count = 3

  labels = {
    env = "production"
  }

  workload_identity_config {
    identity_namespace = "your-gcp-project-id.svc.id.goog"
  }

  dynamic "logging_service" {
    for_each = [
      {
        component = "SYSTEM.METRIC"
        enabled   = true
      },
      {
        component = "SYSTEM_LOG"
        enabled   = true
      },
    ]

    content {
      component                  = logging_service.value.component
      enable_automatic_logging   = true
      exclude_namespaces         = []
      include_namespaces         = ["*"]
      enable_components_in_logs  = {
        workload = ["audit_log"]
      }

      if logging_service.value.component == "SYSTEM_LOG" {
        destination_config {
          log_sink  = google_logging_config.mks_cluster_logs.name
        }
      }
    }
  }
}
```

*Make sure to replace `your-gcp-project-id` with your actual Google Cloud project ID, and `arn:aws:logs:us-east-1:123456789012:log-group:java-kafka` with your correct AWS CloudWatch Logs ARN.*

