provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "firehose" {
  name = "MSK_KinesisFirehoseRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_policy" "firehose" {
  name        = "MSK_KinesisFirehosePolicy"
  description = "Allow Firehose to write to Kinesis Stream and S3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject",
          "s3:PutObjectAcl"
        ]
        Resource = [
          "arn:aws:s3:::your-s3-bucket/*",
          "arn:aws:s3:::your-s3-bucket"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = "arn:aws:kinesis:us-east-1:123456789012:stream/your-kinesis-stream"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose" {
  role       = aws_iam_role.firehose.name
  policy_arn = aws_iam_policy.firehose.arn
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "msk-kinesis-firehose"
  destination = "extended_s3"

  kinesis_source_configuration {
    kinesis_stream_arn = "arn:aws:kinesis:us-east-1:123456789012:stream/your-kinesis-stream"
    role_arn           = aws_iam_role.firehose.arn
  }

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose.arn
    bucket_arn = "arn:aws:s3:::your-s3-bucket"

    buffer_size       = 10
    buffer_interval   = 300
    compression_format = "UNCOMPRESSED"
  }
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  sku_info {
    broker_node_group_info {
      instance_type  = "kafka.m5.large"
      ebs_volume_size = 1000
      client_subnets = [aws_subnet.private_subnet.id]
      security_groups = [aws_security_group.msk.id]
    }
  }

  configuration_info {
    arn = "arn:aws:msk-configuration:us-east-1:123456789012:configuration/kafka-3.1.1"
    revision = "1"
  }

  kafka_version = "2.8.1"
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled = true
      }
    }
  }

  network_info {
    security_groups = [aws_security_group.msk.id]
    subnets         = [aws_subnet.private_subnet.id]
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
        ssl_enabled       = false
      }
    }
  }
}

resource "aws_security_group" "msk" {
  name        = "msk-security-group"
  description = "Allow Kafka traffic"
  vpc_id      = "vpc-12345678"
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id     = "vpc-12345678"
  cidr_block = "10.0.1.0/24"
}
