response:
```hcl
provider "google" {
  project = "your-gcp-project-id"
  region  = "us-east1"
}

resource "google_cersistent_disk" "msk_disks" {
  count = 3
  name  = "msk-disk-${count.index}"
  type  = "pd-standard"
  size  = 10
  region = "us-east1"
}

resource "google_compute_instance" "msk_broker" {
  count = 3
  name         = "msk-broker-${count.index}"
  machine_type = "n1-standard-4"
  zone         = "us-east1-b"

  boot_disk {
    initialize_params {
      image = "cos-cloud/cos-stable"
    }
  }

  attached_disk {
    source = google_persistent_disk.msk_disks[count.index].id
  }

  network_interface {
    network = "default"
    access_config {}
  }

  metadata_startup_script = <<-EOT
    #!/bin/bash

    export PATH=$PATH:/opt/bitnami/msk/bin

    # Install MSK
    /opt/bitnami/scripts/msk/setup.sh
    /opt/bitnami/scripts/msk/configure.sh
  EOT

  lifecycle {
    ignore_changes = [attached_disk]
  }
}

resource "google_service_account" "msk_sa" {
  account_id   = "msk-service-account"
  display_name = "MSK Service Account"
}

resource "google_project_iam_member" "msk_role" {
  project = "your-gcp-project-id"
  role    = "roles/compute.remoteAccess"
  member  = "serviceAccount:${google_service_account.msk_sa.email}"
}

output "msk_instance_ips" {
  value = [for instance in google_compute_instance.msk_broker : instance.network_interface.0.access_config.0.nat_ip]
}
```

Make sure to replace `"your-gcp-project-id"` with your actual GCP project ID. Additionally, have the necessary prerequisites and permissions set up in GCP for creating service accounts and instances.

