resource "google_artifact_registry_repository" "msk_artifacts" {
  provider = "google-beta"
  location = "us-east1"
  repository_id = "msk-artifacts"
  description = "MSK artifacts repository"
  format = "CLOUDEAR"
}

resource "google_msk_cluster" "msk_cluster" {
  name     = "msk-cluster"
  location = "us-east1"

  kafka_config {
    disk_size_gb = 100
  }

  default_engine_config {
    tier    = "STANDARD"
    labels {
      environment = "production"
    }
  }

  networking_config {
    ip_allocation_policy {
      use_ip_aliases = true

      network    = "default"
      subnetwork = "default"
    }
  }

  kafka_versions = ["2.8.1"]

  bootstrap_brokers {
    bootstrap = "b-0.msk-cluster-us-east1.default.kafka.metastack.io:9092"
  }

  topics {
    name               = "example-topic"
    num_partitions     = 1
    storage_bytes_per_partition = 1024
  }

  broker_node_config {
    zone = "us-east1-b"
    instance_type = "nano"
    replicas = 3
  }
}

