provider "aws" {
  region = "us-east-1" # Update to your desired region
}

resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example_subnet" {
  vpc_id     = aws_vpc.example_vpc.id
  cidr_block  = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_security_group" "example_sg" {
  vpc_id = aws_vpc.example_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.1.0/24"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_msk_cluster" "example_msk_cluster" {
  name            = "exampleCluster"
  endpoint_private_tls_enabled = true

  kafka_bootstrap_servers = [
    "node1.exampleCluster.kafka.bootstrap:9091",
    "node2.exampleCluster.kafka.bootstrap:9091",
    "node3.exampleCluster.kafka.bootstrap:9091"
  ]

  client_authentication {
    sasl_scram_enabled = true
    tlsEnabled        = true
  }

  storage_mode = "Standard-1"
  encryption_in_transit {
    client_authentication = true
  }
}

resource "aws_msk_configuration" "example_msk_config" {
  cluster_arn         = aws_msk_cluster.example_msk_cluster.arn
  kafka_version       = "2.8.1"

  client_authentication {
    mechanism = "SASL_SCRAM_aws@gmail.com"
    sasl_scram_enabled = true
    scram_static_authentication {
      secret_arn = aws_secretsmanager_secret.example_secrets.arn
    }
  }

  encryption_in_transit {
    enable      = true
  }

  open_monitoring {
    enable = true
    client_subnets = [aws_security_group.example_sg.id]
  }
}

resource "aws_s3_bucket" "example_s3_bucket" {
  bucket = "example-s3-bucket"
  acl   = "private"
