  }
}

resource "aws_msk_connect_kafka_connector" "example_connector" {
  broker_node_group_id = aws_msk_kafka_versions.example_msk_connect_custom_plugin.broker_node_group_id

  class = "io.debezium.internal.nosql.kafka.connect.configuration.style.NosqlDebeziumConnectorConfig"
  config {
    schemas_file_path = "schemata.txt"
