    bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers
  }
  producer {
    max_retries = 3
  }
  tasks_max = 3
  source_config {
    connector.class = "io.debezium.connector.mysql.MySqlConnector"
    tasks.max       = 3
    config {
      database.hostname       = "rds.endpoint"
      database.include.list   = "db1"
      database.history.kafka.bootstrap.servers = aws_msk_cluster.example.bootstrap_brokers
      database.history.kafka.topic = "dbhistory"
      database.server.id      = "1840544207"
      database.whitelist.list = "db1"
      include.list            = ".*"
      database.history.kafka.security.protocol = "SASL_SSL"
      database.history.kafka.sasl.mechanism     = "SCRAM-SHA-512"
      database.history.kafka.sasl.jaas.config   = "org.apache.kafka.common.security.scram.ScramLoginModule required username="scram_user" password="scram_password";"
    }
  }
  target_config {
    connector.class     = "io.debezium.connect.sink.kafkasink.KafkaSinkConnector"
    tasks.max           = 3
    config {
      "topics"           = "db1.transaction"
    }
  }
}

resource "aws_s3_bucket_object" "debezium_plugin" {
  bucket = "plugin-bucket"
  key    = "debezium.zip"
  source = "path/to/debezium.zip"
}
```

