resource "google_mysql_instance" "primary" {
  name             = "production-mysql-instance"
  project          = "your-gcp-project-id"
  region           = "us-east1"
  database_version = "MYSQL_5_7"

  settings {
    tier  = "db-n1-tier"
    disk_size = "100"
    disk_type = "pd-standard"

    ip_configuration {
      ipv4_enabled = true
      private_network = "default"
    }
  }

  database_flags = {
    enable_binlog = true,
    binlog_format  = "ROW"
  }

  backup_config {
    enabled  = true
    start_time = "22:00"
  }

  manage_external_pfns = "true",
  external_ip  = "YOUR_EXTERNAL_IP",  # Replace with your external IP if needed
}

resource "google_mysql_instance_alerts" "primary_alerts" {
  instance = google_mysql_instance.primary.id
  alert = [
    {
      display_name = "Disk Usage"
      condition    = "diskUtilPercentage > 80"
      dispatch     = "projects/your-gcp-project-id/locations/us-east1/alertPolicies/your alert policy id"
    }
  ]
}

