    disk_type   = "pd-standard"
    disk_size   = "100"
  }

  database_flags = {
    enable_binlog = true
    binlog_format  = "ROW"
  }

  settings {
    ip_configuration {
      ipv4_enabled = true
    }
    authorized_gae_applications = ["application-id"]
  }
}

