For AWS:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_instance" "example" {
  ami               = "ami-0c02fb55956c7d316" # Replace with a suitable PostgreSQL-compatible AMI ID
  instance_type     = "t2.micro"
  key_name         = "your-key-pair-name" # Replace with an appropriate key name

  connection {
    type        = "ssh"
    user        = "ec2-user" # Adjust this user if using a different AMI
    private_key = file("path-to-your-private-key")
  }

  tags = {
    Name = "example-postgres-instance"
  }
}

resource "aws_security_group" "example" {
  name        = "example-sg"
  description = "Allow PostgresQL access"

  ingress {
    description = "Postgres from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    security_groups = [aws_security_group.example.name]
  }

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    description         = "Allow all outbound traffic"
    from_port          = 0
    to_port            = 0
    protocol          = "-1"
    cidr_blocks       = ["0.0.0.0/0"]
  }

  tags = {
    Name = "example-postgres-instance"
  }
}

resource "null_resource" "install_postgresql" {
  connection {
    host        = aws_instance.example.public_ip
    type        = "ssh"
    user        = "ec2-user"
    private_key = file("path-to-your-private-key")
  }

  provisioner "remote-exec" {
    inline = [
      "sudo su -",
      "sudo yum -y update",
      "sudo yum -y install postgresql-server"
    ]
  }
}

# To setup PostgreSQL, utilize remote-exec or Sysadmin provisioning scripts for database setup:
```

