}

resource "aws_neptune_db" "custom_neptune_cluster" {
  name                          = "custom-neptune-cluster"
  engine                        = "neptune"
  no_master_password            = true
  apply_immediately             = true
  instance_type                = "db.t3.medium" # Choose the instance type as per your requirement
  availability_zone           = "us-east-1a" # Replace with your specific availability zone
}

resource "aws_neptune_db_parameter_group" "custom_parameter_group" {
  name         = "custom-neptune-parameter-group"
  engine_family = "neptune"

  parameter {
    name      = "neptune_enable_tracing"
    value     = "true"
  }

  parameter {
    name      = "neptune_enable_performance_logging"
    value     = "false"
  }
}

