  master_username      = "your_master_username"
  master_password      = "your_master_password"
  db_subnet_group_name = aws_neptune_db_subnet_group.custom_neptune_subnet_group.name
  parameter_group_name = aws_neptune_db_parameter_group.custom_parameter_group.name
  skip_final_snapshot   = true
}

