extracted_code:
provider "aws" {
  region = "us-east-1"
}

resource "aws_db_parameter_group" "neptune_cluster_param_group" {
  name   = "neptune-cluster-param-group"
  family = "neptune3.0"

  parameter {
    name  = "example_parameter"
    value = "example_value"
  }
}

resource "aws_db_instance" "example_neptune_instance" {
  # It's important to note that AWS Neptune doesn't directly support custom parameter groups for individual instances
  # Custom parameters have to be passed as options to the cluster configuration itself.
  identifier                = "example-neptune-instance"
  instance_class            = "db.r5.large"
  engine                    = "neptune"
  db_subnet_group_name      = aws_db_subnet_group.example.name
  # connect_to_cluster should be specified when Neuro DB is integrated into an existing instance
  # connect_to_cluster = aws_neptune_cluster.example.id

  # Assign a custom parameter group
  parameter_group_name = aws_db_parameter_group.neptune_cluster_param_group.name
}

resource "aws_neptune_cluster" "example" {
  cluster_identifier      = "example-neptune-cluster"
  engine                  = "neptune"
  engine_version          = "3.0.0.0"
  db_subnet_group_name    = aws_db_subnet_group.example.name
  // Atlas endpoint access to a Neptune cluster standalone mode
  # access_point = [
  #   {
  #     cluster_identifier = aws_neptune_cluster.example.id
  #     cluster_members    = [aws_neptune_instance.example_neptune_instance.cluster_members[0]]
  #
  #     vpc_id             = "vpc-xxxxxx" # Your VPC ID must be present here for atlas
  #     route_table_id     = "rtb-xxxxxx" # This is the route table for the subnets
  #   }
  # ]

  # Standby instance configuration - can be used for high availability
  availability_zones = ["us-east-1a", "us-east-1b"]

  # Configure parameter group for the cluster
  cluster_parameter_group_name = aws_db_parameter_group.neptune_cluster_param_group.name
}

resource "aws_db_subnet_group" "example" {
  name       = "example-neptune-subnet-group"
  subnet_ids = ["subnet-xxxxxx", "subnet-yyyyyy"]

  tags = {
    Name = "example-neptune-subnet-group"
  }
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_security_group" "neptune_sg" {
  name_prefix = "neptune-sg-"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port       = 8182
    to_port         = 8182
    protocol        = "tcp"
    security_groups = [aws_security_group.instance_sg.id]
  }
}

resource "aws_security_group" "instance_sg" {
  name_prefix = "instance-sg-"
  vpc_id      = aws_vpc.example.id
}

resource "aws_instance" "neptune_instance" {
  ami           = "ami-xxxxxx" # Replace with a valid AWS Linux AMI
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.example.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  tags = {
    Name = "NeptuneInstance"
  }
}

