provider "aws" {
  region = "us-west-2"  # Replace with your desired AWS region
}

resource "aws_redshift_cluster" "example-cluster" {
  cluster_identifier       = "example-cluster-id"
  node_type                = "dc2.large"  # Replace with your desired node type
  number_of_nodes          = 2            # Replace with your desired number of nodes

  master_username         = "masteruser"
  master_user_password   = "yourpassword"
  cluster_type           = "multi-node"  # or "single-node"

  publicly_accessible    = false
  encrypted              = true

  tags = {
    Name = "My Redshift Cluster"
    Environment = "Test"
  }

  vpc_security_group_ids = ["${aws_security_group.example-sg.id}"]
}

resource "aws_redshift_cluster_parameter_group" "example-cluster-parameters" {
  cluster_parameter_group_name = "example-parameter-group"
  cluster_identifier        = aws_redshift_cluster.example-cluster.cluster_identifier
  depends_on               = [aws_redshift_cluster.example-cluster]

  parameter {
    parameter_name  = "max_concurrent_transactions"
    parameter_value = "100"
    apply_type      = "both"
  }

  notification_configuration {
    topic_arn = "${aws_sns_topic.example-topic.arn}"
    sns_topic_arn = "${aws_sns_topic.example-topic.arn}"
    enabled     = true
  }
}

resource "aws_security_group" "example-sg" {
  name        = "example-redshift-cluster-sg"
  vpc_id      = "${aws_vpc.example-vpc.id}"

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"  # Allow all inbound traffic
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
