  bucket = aws_s3_bucket.source_bucket.id

  rule {
    id     = "ReportRule"
    filter {
      prefix = ""
    }

    schedule {
      frequency = "WEHOURLY"
      interval  = 7
    }

    lifecycle {
      enabled = true
    }
  }

  expiration {
    id      = "ExpireOldReports"
    filter {
      prefix = "report/"
    }

    expiration {
      days = 30
    }
  }
}

resource "aws_s3_bucket_object" "report_output" {
  bucket = aws_s3_bucket.report_bucket.id
  key    = "report.csv"
  acl    = "private"

  content = <<EOT
Object,Version ID,Delete Mark,Last Modified
ObjectKey1,VersionID1,,2023-10-07T12:00:00Z
ObjectKey2,VersionID2,,2023-10-07T12:05:00Z
EOT

  # Create a script to generate the CSV report and configure a data pipeline
  # Clarified this is a placeholder to demonstrate delivery of the report.
  provisioner "local-exec" {
    command = <<EOT
python3 <<EOF
import boto3
from datetime import datetime, timedelta

s3 = boto3.client('s3')
bucket_name = '${aws_s3_bucket.source_bucket.bucket}'
report_bucket_name = '${aws_s3_bucket.report_bucket.bucket}'
current_time = datetime.utcnow()
week_ago = current_time - timedelta(days=7)
output = 'Object,Version ID,Delete Mark,Last Modified
'

for obj in s3.list_object_versions(Bucket=bucket_name)['Versions']:
    output += f"{obj['Key']},{obj['VersionId']},{obj.get('IsLatest', False)},{obj['LastModified']}
"

with open('report.csv', 'w') as f:
    f.write(output)

s3.upload_file('report.csv', report_bucket_name, 'report.csv')
EOF
EOT
  }
}

