  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "log/"
}

resource "aws_s3_bucket_policy" "log_bucket_policy" {
  bucket = aws_s3_bucket.log_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "s3:PutObject"
        Effect    = "Allow"
        Resource  = "${aws_s3_bucket.log_bucket.arn}/log/*"
        Principal = {
          Service = "logging.s3.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "AWS:SourceAccount" = aws_caller_identity.current.account_id
            "AWS:SourceArn"     = aws_s3_bucket.main_bucket.arn
          }
        }
      },
    ]
  })
}

