}

resource "aws_iam_role" "codebuild_role" {
  name = "CodeBuildAutograderRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token
      type  = "PLAINTEXT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/<OWNER>/<REPOSITORY>.git"
    git_clone_depth = 1

    authentication {
      type            = "OAUTH"
      resource_id     = "<GITHUB_APP_ID>"
      secret_token    = "<OAUTH_TOKEN>"
    }

    buildspec = <<-EOT
      version: 0.2

      phases:
        install:
          commands:
            - echo Installing dependencies
            - # Add commands specific to the build environment setup
        pre_build:
          commands:
            - echo Pre-build step
            - # Add pre-build commands (e.g., checkout code if needed)
        build:
          commands:
            - echo Building and running tests
            - # Add commands to run student code and store results
        post_build:
          commands:
            - echo Storing results
            - # Add any post-build script to store results
    EOT
  }
}

