provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "autograder_results" {
  bucket = "cs-class-autograder-results"
  acl    = "private"

  tags = {
    Name        = "Autograder Results"
    Environment = "Production"
  }
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_results.bucket
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.bucket
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:4.0"
    type         = "LINUX_CONTAINER"

    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/your-username/your-repo.git"
    }

    environment_variable {
      name  = "BRANCH_NAME"
      value = "main"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-username/your-repo.git"
    buildspec = "buildspec.yml"
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild_autograder_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Effect = "Allow"
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_admin" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess"
}
```

Note: Replace `"https://github.com/your-username/your-repo.git"` with the actual GitHub repository URL and adjust the `region` and other configurations as necessary.

