  name         = "cs-class-autograder"
  description  = "Autograder for CS class students' submissions"
  build_timeout = "5"
  service_role = aws_iam_role.autograder_codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:4.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = true
    service_role                = aws_iam_role.autograder_codebuild_role.arn
    timeout                     = "5"
