    subnet_ids = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }
}

resource "aws_s3_bucket" "submissions_bucket" {
  bucket = "cs-class-submissions-bucket"
  acl    = "private"

