  }
}

resource "aws_codebuild_project" "autograder_project" {
  name         = "cs-class-autograder"
  description  = "Autograder for CS class students' submissions"
  build_timeout = "5"
  service_role = aws_iam_role.autograder_codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:4.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = true
    service_role                = aws_iam_role.autograder_codebuild_role.arn
    timeout                     = "5"
    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.submissions_bucket.bucket
    }
  }

  source {
    type             = "GITHUB"
    location         = "https://github.com/your-repo-path/submissions.git"
  }

  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id
    subnet_ids = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }
}

resource "aws_s3_bucket" "submissions_bucket" {
  bucket = "cs-class-submissions-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name = "submissions-bucket"
  }
}

resource "aws_iam_role" "autograder_codebuild_role" {
  name               = "autograder_codebuild_role"
  assume_role_policy = data.aws_iam_policy_document.assume_role_policy.json
}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type       = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }
}

resource "aws_iam_role_policy" "autograder_codebuild_policy" {
  name   = "autograder_codebuild_policy"
  role   = aws_iam_role.autograder_codebuild_role.id
  policy = data.aws_iam_policy_document.codebuild_policy.json
}

data "aws_iam_policy_document" "codebuild_policy" {
  statement {
    actions   = ["logs:CreateLogGroup",
                 "logs:CreateLogStream",
                 "logs:PutLogEvents",
                 "s3:GetObject",
                 "s3:PutObject",
                 "s3:DeleteObject",
                 "ecr:GetAuthorizationToken",
                 "ecr:BatchCheckLayerAvailability",
                 "ecr:GetDownloadUrlForLayer",
                 "ecr:GetRepositoryPolicy",
                 "ecr:DescribeRepositories",
                 "ecr:ListImages",
                 "ecr:DescribeImages",
                 "ecr:BatchGetImage"]
    resources = ["*"]
  }
}
