  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "vpc_subnet" {
  vpc_id           = aws_vpc.vpc.id
  cidr_block        = "10.0.0.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_security_group" "vpc_sg" {
  name        = "vpc-sg-${var.github_username}"
  vpc_id     = aws_vpc.vpc.id
  ingress {
    from_port   = 0
    to_port     = 0
    protocol   = "-1"
    self        = true
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol   = "-1"
    cidr_blocks = []
  }
}

resource "aws_codebuild_project" "codebuild" {
  name           = "codebuild-project-${var.github_username}"
  description    = "CodeBuild project for ${var.github_username}"
  service_role   = aws_iam_role.codebuild_role.arn
  build_timeout  = 20
  badge = true

  artifacts {
    type      = "S3"
    location = aws_s3_bucket.code_build_output.bucket
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image         = "alpine"
    type         = "LINUX_CONTAINER"
  }

  source {
    type      = "GITHUB"
    auth     = "GITHUB"
    location = "github.com" // replace with actual repository details as needed
  }

  vpc_config {
    vpc_id       = aws_vpc.vpc.id
    subnets       = [aws_subnet.vpc_subnet.id]
    security_group_ids = [aws_security_group.vpc_sg.id]
  }

  source_credential {
    type = "AWS"
    type_name = "GITHUB_TOKEN"
    token   = var.github_token
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-role-${var.github_username}"

  assume_role_policy {
    statement = jsonencode({
      Version = "2012-10-17"
      Statement = {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Sid = ""
      }
    })
  }
}

resource "aws_codebuild_source_credential" "codebuild_source_creds" {
  server_type = "GITHUB"
  token       = var.github_token
}

resource "aws_iam_policy_attachment" "codebuild_policy_attach" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
  roles   = [aws_iam_role.codebuild_role.name]
}

resource "aws_s3_bucket" "code_build_output_access" {
  bucket_acl = "private"
  force_destroy = true

  policy = data.aws_iam_policy_document.aws_s3_policy.json
}

data "aws_iam_policy_document" "aws_s3_policy" {
  statement {
    sid       = ""
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.code_build_output. arn}/*"]
    effect   = "Allow"
    principals {
      type = "AWS"
      identifiers = [aws_iam_role.codebuild_role.arn]
    }
  }
}

output "vpc_id" {
  value = aws_vpc.vpc.id
}

output "security_group_id" {
  value = aws_security_group.vpc_sg.id
}

output "s3_bucket_arn" {
