provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-content-bucket"
  acl    = "private"

  force_destroy = true

  versioning {
    enabled = true
  }

  lifecycle {
    prevent_destroy = false
  }
}

resource "aws_cloudfront_distribution" "video_distribution" {
  enabled     = true
  price_class  = "PriceClass_100"

  origin {
    domain_name = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id   = "S3 Video Bucket"

    s3_origin_config {
      origin_access_identity = "origin-access-identity/cloudfront/${aws_cloudfront_origin_access_identity.video_identity.id}"
    }
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods    = ["GET", "HEAD"]
    target_origin_id = "S3 Video Bucket"
    viewer_protocol_policy = "redirect-to-https"

    forwarded_values {
      query_string   = false
      cookies {
        forward = "none"
      }
    }
  }

  restrictions {
    geo_location {
      country = "US"
    }
    geo_location {
      country = "IN"
    }
    geo_location {
      country = "CN"
    }
    geo_location {
      country = "FR"
    }
    geo_location {
      country = "DE"
    }
    geo_location {
      country = "GB"
    }
    geo_location {
      country = "JP"
    }

    restriction_type = "geo-restriction"
    balance_cloudfront_load = true
  }

  viewer_certificate {
    cloudfront_id  = aws_cloudfront_distribution.video_distribution. 201741260 * 
    # Validation can be done manually via AWS ACM or SSL certificate configured in distribution
    cloudfront_certificate_arn = "arn:aws:cloudfront::1234567890:certificate/ABC123456789"
  }
}

