provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "api_video_store" {
  bucket = "video-streaming-site-content"
  acl    = "private"
}

resource "aws_s3_bucket" "api_aws_cloudfront_access_control" {
  bucket = aws_s3_bucket.api_video_store.id

  dynamic "policy" {
    for_each = [
      {
        Version = "2012-10-17"
        Statement = [
          {
            Sid        = "AllowCloudFrontAccess"
            Effect    = "Allow"
            Principal = "cloudfront.amazonaws.com"
            Action    = "s3:GetObject"
            Resource = "${aws_s3_bucket.api_video_store.  arcket}/${var.default_origin_access_id}"
          }
        ]
      }
    ]
  }
}

resource "aws_cloudfront_distribution" "video_streaming_distribution" {
  enabled             = true
  origins {
    domain_name = aws_s3_bucket.api_video_store.bucket_region_domain_name
    origin_id     = "S3${aws_s3_bucket.api_video_store.id}"
  }

  default_cache_behavior {
    target_origin_id       = "S3${aws_s3_bucket.api_video_store.id}"
    viewer_protocol_policy = "allow-all"
  }

  alias {
    name          = "video-streaming-site"
    zone_id       = ${aws_route53_zone.video_zone.zone_id}
  }
}

resource "aws_route53_zone" "video_zone" {
  name = "video-streaming-site.com"
  private_zone = false
}

resource "aws_route53_record" "video_zone_record" {
  zone_id     = aws_route53_zone.video_zone.zone_id
  name        = "video-streaming-site.com"
  type        = "A"
  aliases    = [ { name = "video-streaming-site.com", zone_id = "${aws_route53_zone.video_zone.zone_id}", evaluate_target_health = true }]
}

output "distribution_domain_name" {
  value = "${aws_cloudfront_distribution.video_streaming_distribution.domain_name}"
}

output "get_origin_access_control" {
  value = "${aws_s3_bucket.api_video_store.name}"
}

