```hcl
provider "aws" {
  region = "us-west-2"
}

module "vpc" {
  source = "terraform-aws-modules/vpc/aws"
  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs = ["us-west-2a", "us-west-2b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets = ["10.0.3.0/24", "10.0.4.0/24"]

  enable_nat_gateway = true
  public_subnet_tags = ["public"]
  private_subnet_tags = ["private"]

  public_subnet_tags = ["public"]
  private_subnet_tags = ["private"]
}

resource "aws_lb" "main" {
  name               = "main-alb"
  internal           = false
  subnets            = [module.vpc.public_subnets]
  load_balancer_type = "application"
}

resource "aws_lb_target_group" "tg" {
  name     = "main-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_target_group_attachment" "tg_attachment" {
  target_group_arn = aws_lb_target_group.tg.arn
  target_id        = aws_instance.web.id
  weight          = 10
}

resource "aws_route53_zone" "static" {
  name = "video-streaming-site.com"
}

resource "aws_route53_record" "lb_alias" {
  zone_id = aws_route53_zone.static.zone_id
  name    = "api"
  type    = "A"

  alias {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}

resource "aws_instance" "web" {
  count = 2
  ami = "ami-0c55b159cbfafe1f0"
  instance_type = "t2.micro"

  tags = {
    Name = "WebServer"
  }

  vpc_security_group_ids = [aws_security_group.web.id]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "web" {
  name        = "web-sg"
  description = "Allow web traffic"
  vpc_id     = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```

This Terraform configuration sets up a basic load-balanced infrastructure for a video streaming site in AWS. It configures a VPC with public and private subnets, and launches multiple EC2 instances. To balance traffic across these instances, we create a load balancer and target group, attaching each instance to this target group. The Route 53 A record is configured to point at the load balancer, ensuring seamless access to the site through a friendly domain name. Adjust AMI, instance type, DNS records, or security group rules as needed to meet specific requirements.

