    protocol    = "tcp"
    security_groups = [aws_security_group.example_security_group]
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
  }

  tags = {
    Name = "MySQL Security Group"
  }
}

resource "aws_db_instance" "example_mysql_instance" {
  identifier          = "example-db"
  engine             = "mysql"
  engine_version     = "8.4.3"
  instance_class     = "db.m4.large"
  allocated_storage  = 5
  db_subnet_group_name = aws_db_subnet_group.example_db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.mysql_security_group.id]
  availability_zone = "us-west-2a"

  tags = {
    Name = "MySQLInstance"
  }
}

resource "aws_db_subnet_group" "example_db_subnet_group" {
  name        = "example-db-subnet-group"
  description = "Subnet group for MySQL"
  subnet_ids  = [aws_subnet.example_subnet.id]

  tags = {
    Name = "MySQL Subnet Group"
  }
}
