provider "aws" {
  region = "us-west-2" # Example region, change as required
}

resource "aws_kms_key" "postgresql_kms_key" {
  description = "KMS key for encrypting PostgreSQL RDS instances"
}

resource "aws_security_group" "postgres_db_sg" {
  name        = "postgres-db-sg"
  description = "Security group for PostgreSQL database instance"
}

resource "aws_db_instance" "postgres_db_instance" {
  identifier            = "my-postgres-db"
  engine               = "postgres"
  engine_version       = "15.4"
  db_instance_class   = "db.r5.large" # Adjust instance class as needed
  db_name             = "mydatabase"
  master_username     = "postgresuser"
  master_password     = "superextrasecret123" # Use AWS Secrets Manager for password
  allocated_storage   = 50
  backups_retention_period = 7
  storage_encrypted     = true
  kms_key_id           = aws_kms_key.postgresql_kms_key.arn

  vpc_security_group_ids = [aws_security_group.postgres_db_sg.id]

  subnet_ids = [
    data.aws_subnet.selected.id, # Assumes you have data sourced for aws_subnet based on an RDS in an AWS subnet
  ]

  availability_zone              = data.aws_availability_zone.selected.zone_id # Assumes availability zones are data sourced
  publicly_accessible         = false
  multi_az                    = true
}

resource "aws_db_parameter_group" "postgres_parameter_group" {
  name                = "my-postgres-parameter-group"
  db_parameter_group_name = "postgresql15"
  description         = "Custom parameter group for PostgreSQL 15"
  parameter {
    name        = "max_connections"
    value       = "200"
    apply_method = "immediate"
  }

  parameter {
    name = "pg_timezone"
    value = "UTC"
    apply_method = "immediate"
  }

  # Additional parameters can be added as required
}

resource "aws_rds_cluster" "cluster" {
  cluster_identifier = "my-cluster"
  engine             = "aurora-postgresql"
  engine_version    = "15.4"
  database_name     = "mydatabase"
  master_username   = "postgresadmin"
  master_password   = "supersecret123" # Use AWS Secrets Manager
  storage_encrypted            = true
  db_cluster_parameter_group_id = aws_db_parameter_group.postgres_parameter_group.id
  vpc_security_group_ids      = [aws_security_group.postgres_db_sg.id]
  availability_zones         = [data.aws_availability_zone.selected.zone_id, data.aws_availability_zone.selected2.zone_id] # Assumes multiple AZs data sourced
}

output "database_endpoint" {
  value = aws_db_instance.postgres_db_instance.endpoint
  description = "The endpoint of the PostgreSQL database"
}

