  name              = "mydb"
  identifier        = "mypostgresdb" # Custom snapshot name identifier
  username          = "postgres"
  password          = "yourpassword"
  vpc_security_group_ids = [aws_security_group.postgres_db.id]
  db_subnet_group_name = aws_db_subnet_group.db_subnets.name
  multi_az          = true
  publicly_accessible = false
  skip_final_snapshot = true
  final_snapshot_identifier = "mystage-snapshot"
  apply_immediately          = true
  backup_retention_period    = 7
  backups_retained           = 7
  copy_tags_to_snapshot      = true
  deletion_protection         = false
  db_parameter_group_name = aws_rds_db_parameter_group.postgres_custom_parameters.name
}

resource "aws_db_parameter_group" "postgres_custom_parameters" {
  name   = "mypostgresdb-custom"
  family = "postgres12"

  parameter {
    name        = "max_connections"
    value       = "100" # Replace with desired value
  }

  parameter {
    name        = "maintenance_work_mem"
    value       = "128MB" # Replace with desired value
  }
}

resource "aws_kms_key" "key" {
  description = "KMS key for encrypting PostgreSQL RDS"
}

resource "aws_security_group" "postgres_db" {
  name_prefix  = "postgresdb"
  vpc_id       = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with desired CIDR blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "tcp"
  }
}

resource "aws_db_subnet_group" "db_subnets" {
  name        = "mypostgresdb-subnets"
  subnet_ids  = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id] # Replace with IDs of your RDS subnets
  tag {
    key   = "rds"
    value = "true"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.1.0/24" # Replace with desired CIDR block for subnet A
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.2.0/24" # Replace with desired CIDR block for subnet B
  availability_zone = "us-west-2a" # Replace with the availability zone of subnet B
}

resource "aws_rds_cluster" "main" {
  cluster_identifier = "mypostgres-cluster"
  master_username    = "postgres"
  master_password    = aws_kms_key.key.arn
  database_name      = "mydatabase"
  db_subnet_group_name = aws_db_subnet_group.db_subnets.name
  storage_encrypted   = true
  kms_key_id         = aws_kms_key.key.arn
  skip_final_snapshot = true
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  final_snapshot_identifier       = "pgsnapshot"
  allocated_storage               = 5
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

