```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
}

resource "aws_security_group" "rds_sg" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

resource "aws_db_instance" "mysql_rds" {
  allocated_storage    = 500
  storage_type        = "gp2"
  engine              = "mysql"
  engine_version      = "5.7"
  instance_class      = "db.t3.medium"
  name               = "mysql-instance"
  username           = "dbuser"
  password           = "dbpassword"
  parameter_group_name = "default.mysql5.7"
  db_subnet_group_name = aws_db_subnet_group.rds_subnet_group.id
  vpc_security_groups = [aws_security_group.rds_sg.id]
  publicly_accessible = true

  tags = {
    Name = "mysql-rds"
  }
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids  = [aws_subnet.public_subnet.id, aws_subnet.private_subnet.id]

  tags = {
    Name = "rds-subnet-group"
  }
}
```

Note: Replace `"mysql-instance"`, `"dbuser"`, `"dbpassword"`, and `"dbpassword"` with actual values to match your specific requirements. This configuration establishes an AWS environment with a VPC, public and private subnets across different availability zones, a security group for database access, and a publicly accessible RDS instance for MySQL with specified storage and version. It also includes assigning a DB subnet group linking to the defined subnets.

