provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

resource "aws_vpc" "custom_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "custom_subnet" {
  vpc_id     = aws_vpc.custom_vpc.id
  cidr_block  = "10.0.1.0/24" # Replace with your desired CIDR block

  map_public_ip_on_launch = true
}

resource "aws_db_instance" "postgres_db" {
  identifier                  = "mydbinstance"
  engine                     = "postgres"
  engine_version             = "14.7"
  db_instance_class         = "db.t3.micro"
  allocated_storage          = 20
  master_username           = "postgresadmin"
  master_user_password      = "mysecurepassword"
  availability_zone         = "us-east-1a"
  backup_retention_period    = 5
  prefer_vpc_subnet          = true
  skip_final_snapshot       = true

  vpc_security_groups = [aws_security_group.postgres_sg.name]
  db_subnet_group_name = aws_db_subnet_group.postgres_db_subnet.name

  publicly_accessible = false

  # Maintenance and backup window settings
  apply_immediately = true
  maintenance_window = "03:00-06:00"
}

resource "aws_security_group" "postgres_sg" {
  name        = "postgres-sg"
  description = "PostgreSQL security group in custom VPC"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24"]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_subnet_group" "postgres_db_subnet" {
  name  = "postgres-sg"
  db_subnet_ids = [aws_subnet.custom_subnet.id]
  vpc_id        = aws_vpc.custom_vpc.id
}

