provider "aws" {
  region = "us-west-2"  # Adjust the region as needed
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "primary" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "secondary" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
}

resource "aws_security_group" "rds_sg" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_subnet_group" "subnet" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.primary.id, aws_subnet.secondary.id]
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name = "db_credentials"
}

resource "aws_secretsmanager_secret_version" "parameter" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = "{"username":"myuser","password":"mypassword"}"
}

resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier      = "aurora-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "5.7.mysql_aurora.2.07.2"
  database_name           = "mydb"
  master_username         = "myuser"
  master_password         = lookup(data.aws_secretsmanager_secret_version.creds.secret_string, "password", "")
  db_subnet_group_name    = aws_db_subnet_group.subnet.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  skip_final_snapshot     = false
  final_snapshot_identifier = "snapshot"
}

resource "aws_secretsmanager_secret_version" "creds" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "myuser",
    password = "mypassword"
  })
}

resource "aws_rds_cluster_instance" "aurora_instances" {
  count             = 2
  identifier        = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  instance_class    = "db.small"
}

resource "aws_appautoscaling_target" "autoscaling_target" {
  max_capacity       = 2
  min_capacity       = 1
  resource_id        = "cluster:${aws_rds_cluster.aurora_cluster.id}"
  scalable_dimension = "rds:cluster:ReadReplicaCount"
  service_namespace  = "rds"
}

resource "aws_appautoscaling_policy" "autoscaling_policy" {
  name               = "aurora-autoscaling-policy"
  policy_type        = "TargetTrackingScaling"
  resource_id        = aws_appautoscaling_target.autoscaling_target.resource_id
  scalable_dimension = aws_appautoscaling_target.autoscaling_target.scalable_dimension
  service_namespace  = aws_appautoscaling_target.autoscaling_target.service_namespace

  target_tracking_scaling_policy_configuration {
    target_value       = 70.0
    predefined_metric_specification {
      predefined_metric_type = "RDSReaderAverageCPUUtilization"
    }
    scale_in_cooldown  = 300
    scale_out_cooldown = 300
  }
}

# RDS Proxy (sample assumable role for proxy)
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_rds_db_cluster_parameter_group" "parameter_group" {
  name   = "rds-proxy-parameter-group"
  family = "auroramysql5.7"
}

resource "aws_rds_proxy" "example" {
  db_cluster_identifier            = aws_rds_cluster.aurora_cluster.id
  db_clustering                     = true
  iam_auth                           = true
  require_tls                       = false
  idle_client_timeout               = 1800
  host_header                       = "rds.amazonaws.com"
  role_arn                          = aws_iam_role.rds_proxy_role.arn
  debug_logger                      = true
  debug_logging_filter_events       = "Connections%2C Commands"
  vpc_security_group_ids            = [aws_security_group.rds_sg.id]
  vpc_subnet_ids                    = [aws_subnet.primary.id, aws_subnet.secondary.id]
}

