resource "aws_dlm_lifecycle_policy" "policy" {
  description       = "S3 Lifecycle Policy"
  execution_role_arn = aws_iam_role.dlm_role.arn

  state                 = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name     = "daily"
      tags_to_add = {
        "DeleteOn" = "2023-12-31"
      }

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["02:00"]
      }

      retain_rule {
        count = 30
      }

      terminate_instances_with_snapshots = true
    }

    target_tags = {
      "GlacierTransition" = "true"
    }

    parameters {
      archive_rule {
        days_after_start = 30
      }
    }
  }
}

resource "aws_iam_role" "dlm_role" {
  name = "dlm-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_policy" "dlm_policy" {
  name   = "DLMPolicy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "ec2:CreateSnapshot",
          "ec2:DeleteSnapshot",
          "ec2:DescribeVolumes",
          "ec2:DescribeInstances",
          "ec2:DescribeSnapshots",
          "s3:GetBucketLocation",
          "s3:GetBucketLifecycle",
          "s3:PutLifecycle",
          "s3:PutAccelerateConfiguration",
          "s3:PutBucketVersioning"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

