provider "aws" {
  region = "us-west-2" # Change this to your desired region
}

resource "aws_eip" "lb_ip" {
  vpc = true
}

resource "aws_elb" "example" {
  name               = "example-elb"
  availability_zones = ["us-west-2a", "us-west-2b", "us-west-2c"]

  listener {
    instance_port     = 80
    instance_protocol = "HTTP"
    lb_port           = 80
    lb_protocol       = "HTTP"
  }

  health_check {
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 3
    target              = "HTTP:80/"
    interval            = 30
  }

  subnet_ids = [aws_subnet.example.id, aws_subnet.example2.id] # Replace with your actual subnet IDs

  connection_draining = true
  connection_draining_timeout = 400

  instances                   = [aws_instance.example.id] # Replace with your instance ID

  idle_timeout                = 400

  cross_zone_load_balancing   = true
  idle_timeout                = 400

  instances = [aws_instance.example.id] # Modify this with your instance IDs

  tags = {
    Name = "example-elb"
  }
}

resource "aws_instance" "example" {
  ami           = "ami-0c55b159cbfafe1f0" # Use an appropriate AMI ID for your use case
  instance_type = "t2.micro"

  tags = {
    Name = "example-instance"
  }
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "example2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
}

resource "aws_security_group" "lb_sg" {
  name        = "load-balancer-sg"
  description = "allow traffic from anywhere"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "load-balancer-sg"
  }
}

resource "aws_network_interface_sg_attachment" "sg_attachment" {
  security_group_id    = aws_security_group.lb_sg.id
  network_interface_id = aws_instance.example.primary_network_interface_id
}

resource "aws_elb_attachment" "example_attachment" {
  elb      = aws_elb.example.id
  instance = aws_instance.example.id
}

resource "aws_eip_association" "lb_eip" {
  allocation_id = aws_eip.lb_ip.id
  network_interface_id = aws_instance.example.primary_network_interface_id
}

