provider "hcp" {
  // Google Cloud provider configuration
}

resource "hcp_lb" "example_lb" {
  name     = "example-lb"
  location = "us-central1"

  network = "projects/YOUR_PROJECT/global/networks/YOUR_NETWORK"

  session_affinity = "NONE"

  network_ip = "10.0.1.10"

  tags = ["http", "example"]

  backend_services {
    name               = "example-backend-service"
    port_name          = "http"
    timeout_sec        = 10
    consistent_hash    = false
    health_checks {
      name = "example-health-check"
    }
    load_balancing_scheme              = "EXTERNAL"
    circuit_breakers {
      thresholds {
        max_connections                 = 100
        max_requests                    = 100
        max_retries                     = 3
      }
    }
  }
}

resource "hcp_health_check" "example_health_check" {
  name           = "example-health-check"
  type           = "HTTP"
  http_health_check {
    port         = 80
    request_path = "/health"
  }
}

resource "hcp_url_map" "example_url_map" {
  name            = "example-url-map"
  default_service = hcp_backend_bucket.example.services[0].name

  host_rule {
    hosts        = ["*"]
    path_matcher = "allpaths"
  }

  path_matcher {
    name               = "allpaths"
    default_service    = hcp_backend_bucket.example.services[0].name
    path_rule {
      paths   = ["/"]
      service = hcp_backend_bucket.example.services[0].name
    }
  }
}

resource "hcp_backend_bucket" "example" {
  name = "example-backend-bucket"

  backend {
    group = "default"
    bucket = "gcs://your-bucket-name"
    balancing_mode = "CONNECTION"
    max_connections_per_instance = 1000
  }
}

resource "hcp_managed_certificate" "example_certificate" {
  name = "example-cert"

  managed {
    domains = ["your-oidc-domain"]
  }
}

resource "hcp_iap_web_backend_service" "example_iap" {
  for_each = {
    "temp-oidc-url-map" = true
  }
  name        = each.key
  description = "Load Balancer with Authenticate-OIDC"
  url_map     = hcp_url_map.example_url_map.id

  authentication = "AUTHORIZED_OAUTH_SPONSORS"
  oauth {
    audiences = ["https://www.googleapis.com/oauth2/v1/apps/YOUR_OAUTH_CLIENT_ID"]

    allow_partial_success = false
    oauth_mode            = "ACCESS_TOKEN"
  }

  authorized_networks = [
    "YOUR_NETWORK_IP"
  ]

  client_tls_policy {
    client_certificate_mode    = "NONE"
  }

  logging {
    enable          = true
    sample_rate     = 1.0
  }

  project            = "YOUR_PROJECT"
}

resource "hcp_global_address" "example" {
  name = "example-address"
}

resource "hcp_target_pool" "example" {
  name = "example-target-pool"

  health_checks = [
    hcp_health_check.example_health_check.id
  ]
}

resource "hcp_forwarding_rule" "example" {
  name       = "example-forwarding-rule"
  region     = "us-central1"
  ip_address = hcp_global_address.example.address

  load_balancing_scheme = "EXTERNAL"
  backend_service       = hcp_target_pool.example.id

  ip_protocol          = "TCP"
  ports                = ["80"]
  target               = hcp_target_pool.example.id
  allowed_ports        = ["80"]
  network              = "projects/YOUR_PROJECT/global/networks/YOUR_NETWORK"
}

