  }

  tags = {
    Name = "main-route-table"
  }
}

variable "public_subnets" {
  type = list(string)
  default = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
}

resource "aws_subnet" "public_subnets" {
  count = length(var.public_subnets)

  vpc_id           = aws_vpc.main_vpc.id
  cidr_block        = element(var.public_subnets, count.index)
  map_public_ip_on_launch = true
  availability_zone = ["us-west-2a", "us-west-2b", "us-west-2c"][count.index]

  tags = {
    Name = "public-subnet-${count.index}"
  }
}

resource "aws_route_table_association" "public_rt_associations" {
  count             = length(var.public_subnets)
  route_table_id    = aws_route_table.main_route_table.id
  subnet_id         = element(aws_subnet.public_subnets.*.id, count.index)
}

resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "private-route-table"
  }
}

resource "aws_command" "public_routing_command" {
  count = length(var.public_subnets)
  command = "aws ec2 associate-route --route-table-id ${aws_route_table.main_route_table.id} --subnet-id ${aws_subnet.public_subnets[count.index].id} --route-id id${element(aws_subnet.public_subnets.*.id, count.index}/${element(aws_subnet.public_subnets.*.route_table_association.route_table_id, count.index)}"
}

